233: export class ExtHostDiagnostics implements ExtHostDiagnosticsShape {
234: 
235: 	private static _idPool: number = 0;
236: 	private static readonly _maxDiagnosticsPerFile: number = 1000;
237: 	private static readonly _maxDiagnosticsTotal: number = 1.1 * this._maxDiagnosticsPerFile;
238: 
239: 	private readonly _proxy: MainThreadDiagnosticsShape;
240: 	private readonly _collections = new Map<string, DiagnosticCollection>();
241: 	private readonly _onDidChangeDiagnostics = new DebounceEmitter<readonly vscode.Uri[]>({ merge: all => all.flat(), delay: 50 });
242: 
243: 	static _mapper(last: readonly vscode.Uri[]): { uris: readonly vscode.Uri[] } {
244: 		const map = new ResourceMap<vscode.Uri>();
245: 		for (const uri of last) {
246: 			map.set(uri, uri);
247: 		}
248: 		return { uris: Object.freeze(Array.from(map.values())) };
249: 	}
250: 
251: 	readonly onDidChangeDiagnostics: Event<vscode.DiagnosticChangeEvent> = Event.map(this._onDidChangeDiagnostics.event, ExtHostDiagnostics._mapper);
252: 
253: 	constructor(
254: 		mainContext: IMainContext,
255: 		@ILogService private readonly _logService: ILogService,
256: 		@IExtHostFileSystemInfo private readonly _fileSystemInfoService: IExtHostFileSystemInfo,
257: 		private readonly _extHostDocumentsAndEditors: ExtHostDocumentsAndEditors,
258: 	) {
259: 		this._proxy = mainContext.getProxy(MainContext.MainThreadDiagnostics);
260: 	}
261: 
262: 	createDiagnosticCollection(extensionId: ExtensionIdentifier, name?: string): vscode.DiagnosticCollection {
263: 
264: 		const { _collections, _proxy, _onDidChangeDiagnostics, _logService, _fileSystemInfoService, _extHostDocumentsAndEditors } = this;
265: 
266: 		const loggingProxy = new class implements MainThreadDiagnosticsShape {
267: 			$changeMany(owner: string, entries: [UriComponents, IMarkerData[] | undefined][]): void {
268: 				_proxy.$changeMany(owner, entries);
269: 				_logService.trace('[DiagnosticCollection] change many (extension, owner, uris)', extensionId.value, owner, entries.length === 0 ? 'CLEARING' : entries);
270: 			}
271: 			$clear(owner: string): void {
272: 				_proxy.$clear(owner);
273: 				_logService.trace('[DiagnosticCollection] remove all (extension, owner)', extensionId.value, owner);
274: 			}
275: 			dispose(): void {
276: 				_proxy.dispose();
277: 			}
278: 		};
279: 
280: 
281: 		let owner: string;
282: 		if (!name) {
283: 			name = '_generated_diagnostic_collection_name_#' + ExtHostDiagnostics._idPool++;
284: 			owner = name;
285: 		} else if (!_collections.has(name)) {
286: 			owner = name;
287: 		} else {
288: 			this._logService.warn(`DiagnosticCollection with name '${name}' does already exist.`);
289: 			do {
290: 				owner = name + ExtHostDiagnostics._idPool++;
291: 			} while (_collections.has(owner));
292: 		}
293: 
294: 		const result = new class extends DiagnosticCollection {
295: 			constructor() {
296: 				super(
297: 					name!, owner,
298: 					ExtHostDiagnostics._maxDiagnosticsTotal,
299: 					ExtHostDiagnostics._maxDiagnosticsPerFile,
300: 					uri => _extHostDocumentsAndEditors.getDocument(uri)?.version,
301: 					_fileSystemInfoService.extUri, loggingProxy, _onDidChangeDiagnostics
302: 				);
303: 				_collections.set(owner, this);
304: 			}
305: 			override dispose() {
306: 				super.dispose();
307: 				_collections.delete(owner);
308: 			}
309: 		};
310: 
311: 		return result;
312: 	}
313: 
314: 	getDiagnostics(resource: vscode.Uri): ReadonlyArray<vscode.Diagnostic>;
315: 	getDiagnostics(): ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>;
316: 	getDiagnostics(resource?: vscode.Uri): ReadonlyArray<vscode.Diagnostic> | ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]>;
317: 	getDiagnostics(resource?: vscode.Uri): ReadonlyArray<vscode.Diagnostic> | ReadonlyArray<[vscode.Uri, ReadonlyArray<vscode.Diagnostic>]> {
318: 		if (resource) {
319: 			return this._getDiagnostics(resource);
320: 		} else {
321: 			const index = new Map<string, number>();
322: 			const res: [vscode.Uri, vscode.Diagnostic[]][] = [];
323: 			for (const collection of this._collections.values()) {
324: 				collection.forEach((uri, diagnostics) => {
325: 					let idx = index.get(uri.toString());
326: 					if (typeof idx === 'undefined') {
