338: 	private _getDiagnostics(resource: vscode.Uri): ReadonlyArray<vscode.Diagnostic> {
339: 		let res: vscode.Diagnostic[] = [];
340: 		for (const collection of this._collections.values()) {
341: 			if (collection.has(resource)) {
342: 				res = res.concat(collection.get(resource));
343: 			}
344: 		}
345: 		return res;
346: 	}
347: 
348: 	private _mirrorCollection: vscode.DiagnosticCollection | undefined;
349: 
350: 	$acceptMarkersChange(data: [UriComponents, IMarkerData[]][]): void {
351: 
352: 		if (!this._mirrorCollection) {
353: 			const name = '_generated_mirror';
354: 			const collection = new DiagnosticCollection(
355: 				name, name,
356: 				Number.MAX_SAFE_INTEGER, Number.MAX_SAFE_INTEGER, // no limits because this collection is just a mirror of "sanitized" data
357: 				_uri => undefined,
358: 				this._fileSystemInfoService.extUri, undefined, this._onDidChangeDiagnostics
359: 			);
360: 			this._collections.set(name, collection);
361: 			this._mirrorCollection = collection;
362: 		}
363: 
364: 		for (const [uri, markers] of data) {
365: 			this._mirrorCollection.set(URI.revive(uri), markers.map(converter.Diagnostic.to));
366: 		}
367: 	}
368: }
