   181→	/** Handles a request for a remote method call, invoking `fn` and returning the result */
   182→	const remoteMethod = async (req, response, fn) => {
   183→		const params = await new Promise((resolve, reject) => {
   184→			const body = [];
   185→			req.on('data', chunk => body.push(chunk));
   186→			req.on('end', () => resolve(JSON.parse(Buffer.concat(body).toString())));
   187→			req.on('error', reject);
   188→		});
