   190→			const result = await fn(...params);
   191→			response.writeHead(200, { 'Content-Type': 'application/json' });
   192→			response.end(JSON.stringify(result));
   193→		} catch (err) {
   194→			response.writeHead(500);
   195→			response.end(err.message);
   196→		}
   197→	};
   198→
   199→	const server = http.createServer((request, response) => {
   200→		if (!request.url?.startsWith(prefix)) {
   201→			return response.writeHead(404).end();
   202→		}
