	private readonly _fileChangeListener: IDisposable;

	constructor(
		extHostContext: IExtHostContext,
		@IMarkerService private readonly _markerService: IMarkerService,
		@IUriIdentityService private readonly _uriIdentService: IUriIdentityService,
		@IFileService private readonly _fileService: IFileService,
	) {
		this._proxy = extHostContext.getProxy(ExtHostContext.ExtHostDiagnostics);

		this._markerListener = this._markerService.onMarkerChanged(this._forwardMarkers, this);
		this._fileChangeListener = this._fileService.onDidFilesChange(e => this._onDidFilesChange(e));
	}

	dispose(): void {
		this._markerListener.dispose();
		this._fileChangeListener.dispose();
		this._activeOwners.forEach(owner => this._markerService.changeAll(owner, []));
		this._activeOwners.clear();
	}

	private _forwardMarkers(resources: readonly URI[]): void {
		const data: [UriComponents, IMarkerData[]][] = [];
		for (const resource of resources) {
			const allMarkerData = this._markerService.read({ resource });
			if (allMarkerData.length === 0) {
				data.push([resource, []]);
			} else {
				const forgeinMarkerData = allMarkerData.filter(marker => !this._activeOwners.has(marker.owner));
				if (forgeinMarkerData.length > 0) {
					data.push([resource, forgeinMarkerData]);
				}
			}
		}
		if (data.length > 0) {
			this._proxy.$acceptMarkersChange(data);
		}
	}

	private _onDidFilesChange(event: any): void {
		// Clear diagnostics for files that have been deleted
		for (const resource of event.rawDeleted) {
			const canonicalUri = this._uriIdentService.asCanonicalUri(resource);
			// Clear all markers for this resource
			this._activeOwners.forEach(owner => {
				this._markerService.changeOne(owner, canonicalUri, []);
			});
		}

		// For changed/updated files, clear existing diagnostics to allow re-analysis
		// This helps fix stale diagnostics after Git operations like branch switches
		const changedResources = [...event.rawAdded, ...event.rawUpdated];
		const data: [UriComponents, IMarkerData[]][] = [];
		for (const resource of changedResources) {
			const canonicalUri = this._uriIdentService.asCanonicalUri(resource);
			const allMarkerData = this._markerService.read({ resource: canonicalUri });

			// Only clear markers from active owners (extension-provided diagnostics)
			// to allow them to refresh on the next analysis
			if (allMarkerData.some(marker => this._activeOwners.has(marker.owner))) {
				data.push([resource, []]);
				for (const owner of this._activeOwners) {
					this._markerService.changeOne(owner, canonicalUri, []);
				}
			}
		}

		// Notify the extension host about the cleared diagnostics
		if (data.length > 0) {
			this._proxy.$acceptMarkersChange(data);
		}
	}

	$changeMany(owner: string, entries: [UriComponents, IMarkerData[]][]): void {
		for (const entry of entries) {
			const [uri, markers] = entry;
			if (markers) {
				for (const marker of markers) {
					if (marker.relatedInformation) {
						for (const relatedInformation of marker.relatedInformation) {
							relatedInformation.resource = URI.revive(relatedInformation.resource);
						}
					}
					if (marker.code && typeof marker.code !== 'string') {
						marker.code.target = URI.revive(marker.code.target);
					}
				}
			}
			this._markerService.changeOne(owner, this._uriIdentService.asCanonicalUri(URI.revive(uri)), markers);
		}
		this._activeOwners.add(owner);
	}

	$clear(owner: string): void {
		this._markerService.changeAll(owner, []);
		this._activeOwners.delete(owner);
	}
}

